import pytest
from deepeval import assert_test
from deepeval.test_case import LLMTestCase
from deepeval.metrics import AnswerRelevancyMetric, FaithfulnessMetric

# Fixtures
@pytest.fixture(scope="module")
def judge():
    return AnthropicJudge()

CASES = [
    {
        "input": "What is the cancellation window?",
        "actual_output": "Bookings can be cancelled up to 48 hours before for a full refund.",
        "expected_output": "48 hours notice required for a full refund.",
        "context": ["Full refund for cancellations more than 48 hours in advance."],
    },
    {
        "input": "Can I change my booking date?",
        "actual_output": "Yes, date changes are free if made at least 72 hours in advance.",
        "expected_output": "Date changes are free with 72 hours notice.",
        "context": ["Date reschedules are free when requested 72+ hours before the booking."],
    },
]

@pytest.mark.parametrize("case_data", CASES)
def test_support_agent(judge, case_data):
    case = LLMTestCase(
        input=case_data["input"],
        actual_output=case_data["actual_output"],
        expected_output=case_data["expected_output"],
        retrieval_context=case_data["context"],
    )
    assert_test(case, [
        AnswerRelevancyMetric(minimum_score=0.8, model=judge),
        FaithfulnessMetric(minimum_score=0.9, model=judge),
    ])

from deepeval.metrics import BaseMetric
from deepeval.test_case import LLMTestCase
import re

class OrderIdCitedMetric(BaseMetric):
    """Checks whether the response includes an order ID reference."""

    def __init__(self, minimum_score: float = 1.0):
        self.minimum_score = minimum_score
        self.score: float = 0.0
        self.reason: str = ""

    @property
    def name(self) -> str:
        return "order_id_cited"

    def measure(self, test_case: LLMTestCase) -> float:
        output = test_case.actual_output or ""
        match = re.search(r"(#\d{6,10}|ORD-\d{6,10})", output)
        if match:
            self.score = 1.0
            self.reason = f"Order ID found: {match.group()}"
        else:
            self.score = 0.0
            self.reason = "No order ID pattern found in response."
        return self.score

    async def a_measure(self, test_case: LLMTestCase) -> float:
        # Synchronous check — async wrapper delegates to measure()
        return self.measure(test_case)

    def is_successful(self) -> bool:
        return self.score >= self.minimum_score

# Use alongside built-in metrics
metrics = [
    FaithfulnessMetric(minimum_score=0.9, model=judge),
    OrderIdCitedMetric(minimum_score=1.0),
]
